  akali: { diff: "HARD", tone: "#ff5d6c", tldr: "Build MR \u2014 Q-hook her off shroud, chain CC.", breakdown: "Build MR, Q-hook her before/off her shroud, and chain CC her burst.", dos: ["Build MR", "Q-hook her off the shroud", "E-slow + root her"], donts: ["Fight her 6 with no MR", "Get Q-poked down", "Chase her into shroud"], key: { slot: "W", name: "Twilight Shroud", cd: "18s", note: "Untargetable inside \u2014 hook needs a target.", winT: "SHROUD DOWN", winS: "Q-E + R her." }, hold: "Hold Q to hook her before she shrouds (it needs a target) \u2014 chain CC her burst.", tip: "Build MR and Q-hook her before the shroud \u2014 chain CC to lock her down.", win: "Build MR and hook her off shroud." },
