  jayce: { diff: "HARD", tone: "#ff5d6c", tldr: "He pokes you out \u2014 build a little armor, Q-hook him.", breakdown: "Jayce out-pokes you. Build a little armor, Q-hook onto him, and chain CC to close the gap.", dos: ["Build a little armor", "Q-hook onto him", "E-slow + root him"], donts: ["Walk into his Q-gate", "Get E-knocked", "Let the poke war drag"], key: { slot: "Q", name: "Shock Blast", cd: "6s", note: "His main poke. Dodge it.", winT: "SHOCK BLAST DOWN", winS: "Q-E + R him." }, hold: "Hold Q to hook onto him \u2014 the self-pull closes his range past his poke; chain CC after.", tip: "Build a little armor and Q-hook onto him \u2014 the self-pull closes the gap; chain CC to lock him.", win: "Hook onto him and chain CC." },
  kayle: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Build mixed \u2014 Q-hook her early, deny her CS.", breakdown: "Kayle scales hard. Build mixed resists, Q-hook her off CS early, and chain CC before her R.", dos: ["Build mixed resists", "Q-hook her off CS", "Out-trade before her R"], donts: ["Let her free-farm", "Fall behind in scaling", "Fight late from behind"], key: { slot: "R", name: "Divine Judgment (Invuln)", cd: "100s", note: "Her get-out at 6. Bait it.", winT: "JUDGMENT DOWN", winS: "Q-E + R her." }, hold: "Hold Q to hook her off a CS \u2014 chain CC to deny her farm and snowball.", tip: "Build mixed resists and Q-hook her off CS early \u2014 chain CC before her scaling kicks in.", win: "Hook her off CS and chain CC." },
  kennen: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Build MR \u2014 Q-hook him, chain CC his poke.", breakdown: "Build MR, Q-hook him before his E, and chain CC his squishy kit.", dos: ["Build MR", "Q-hook before his E", "E-slow + root him"], donts: ["Eat free Q pokes", "Get triple-stunned", "Fall behind in scaling"], key: { slot: "E", name: "Lightning Rush", cd: "10s", note: "His escape. Hook before it.", winT: "E DOWN", winS: "Q-E + R him." }, hold: "Hold Q to hook him before his E \u2014 chain CC his squishy kit.", tip: "Build MR and Q-hook him before his E \u2014 chain CC to lock him down.", win: "Build MR and chain CC him." },
  quinn: { diff: "HARD", tone: "#ff5d6c", tldr: "She pokes + kites \u2014 Q-hook her kite, all-in early.", breakdown: "Quinn out-pokes you. Q-hook onto her (stops her kite), chain CC, and all-in early.", dos: ["Q-hook onto her", "Chain CC her kite", "All-in early"], donts: ["Fight into her blind", "Poke-war from range", "Let her kite you out"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Her self-peel. Hook around it.", winT: "VAULT DOWN", winS: "Q-E + R her." }, hold: "Hold Q to hook onto her \u2014 the self-pull + chain CC stops her kite; all-in early.", tip: "Q-hook onto her to close the gap \u2014 chain CC stops her kite, then all-in before she scales.", win: "Hook her kite and all-in early." },
