  swain: { diff: "TRICKY", tone: "#ff8b3d", tldr: "His AP drain + root \u2014 build MR, Q-hook him.", breakdown: "Swain\u2019s magic drain ignores armor. Build MR, Q-hook him, and dodge his E root.", dos: ["Build MR", "Q-hook into chain CC", "Dodge his E root"], donts: ["Build armor vs his AP", "Fight into his R drain", "Get E-rooted"], key: { slot: "R", name: "Demonic Ascension", cd: "100s", note: "His drain. Chain CC when it\u2019s down.", winT: "ASCENSION DOWN", winS: "Q-E + R him." }, hold: "Hold Q to hook him in \u2014 chain CC; build MR since his drain is magic.", tip: "He\u2019s AP drain \u2014 build MR, Q-hook into chain CC, and dodge his E root; fight when his R is down.", win: "Build MR and chain CC off his R." },
